     3|/// Owner session data returned by the IVX auth proxy.
     4|struct OwnerSession: Codable, Equatable {
     5|    let accessToken: String
     6|    let refreshToken: String?
     7|    let expiresAt: Int?
     8|    let tokenType: String
     9|    let userId: String?
    10|    let email: String?
    11|    let emailConfirmed: Bool?
    12|    let role: String?
    13|    let accountType: String?
    14|    let firstName: String?
    15|    let lastName: String?
    16|
    17|    var isExpired: Bool {
    18|        guard let expiresAt = expiresAt else { return false }
    19|        return Date(timeIntervalSince1970: TimeInterval(expiresAt)) <= Date()
    20|    }
    21|
    22|    var displayName: String {
    23|        if let firstName = firstName, !firstName.isEmpty {
    24|            return lastName?.isEmpty == false ? "\(firstName) \(lastName ?? "")" : firstName
    25|        }
    26|        return email ?? "Owner"
    27|    }
    28|}
