     1|import Foundation
     2|import SwiftUI
     3|
     4|/// Auth ViewModel — manages owner session state, persistence, and login/recovery flows.
     5|@Observable
     6|final class AuthViewModel {
     7|    var state: AuthState = .loading
     8|    var diagnostic: AuthDiagnostic?
     9|    var isLoading: Bool = false
    10|
    11|    private let service = IVXAuthService.shared
    12|    private let sessionKey = "ivx_owner_session"
    13|
    14|    init() {
    15|        restoreSession()
    16|    }
    17|
    18|    // MARK: - Session Persistence
    19|
    20|    private func restoreSession() {
    21|        guard let data = UserDefaults.standard.data(forKey: sessionKey) else {
    22|            state = .unauthenticated
    23|            return
    24|        }
    25|        do {
    26|            let session = try JSONDecoder().decode(OwnerSession.self, from: data)
    27|            if session.isExpired {
    28|                Task { await refreshSession(session) }
    29|            } else {
    30|                state = .authenticated(session)
    31|            }
    32|        } catch {
    33|            state = .unauthenticated
    34|        }
    35|    }
    36|
    37|    private func saveSession(_ session: OwnerSession) {
    38|        do {
    39|            let data = try JSONEncoder().encode(session)
    40|            UserDefaults.standard.set(data, forKey: sessionKey)
    41|        } catch {
    42|            // Non-fatal — session still works in memory
    43|        }
    44|    }
    45|
    46|    private func clearSession() {
    47|        UserDefaults.standard.removeObject(forKey: sessionKey)
    48|    }
    49|
    50|    // MARK: - Login
    51|
    52|    func login(email: String, password: String) async {
    53|        isLoading = true
    54|        defer { isLoading = false }
    55|        do {
    56|            let session = try await service.login(email: email, password: password)
    57|            saveSession(session)
    58|            state = .authenticated(session)
    59|        } catch {
    60|            state = .error(error.localizedDescription)
    61|        }
    62|    }
    63|
    64|    // MARK: - Refresh
    65|
    66|    private func refreshSession(_ oldSession: OwnerSession) async {
    67|        guard let refreshToken = oldSession.refreshToken else {
    68|            state = .unauthenticated
    69|            return
    70|        }
    71|        do {
    72|            let newSession = try await service.refreshSession(refreshToken: refreshToken)
    73|            let merged = OwnerSession(
    74|                accessToken: newSession.accessToken,
    75|                refreshToken: newSession.refreshToken ?? oldSession.refreshToken,
    76|                expiresAt: newSession.expiresAt,
    77|                tokenType: newSession.tokenType,
    78|                userId: oldSession.userId,
    79|                email: oldSession.email,
    80|                emailConfirmed: oldSession.emailConfirmed,
    81|                role: oldSession.role,
    82|                accountType: oldSession.accountType,
    83|                firstName: oldSession.firstName,
    84|                lastName: oldSession.lastName
    85|            )
    86|            saveSession(merged)
    87|            state = .authenticated(merged)
    88|        } catch {
    89|            clearSession()
    90|            state = .unauthenticated
    91|        }
    92|    }
    93|
    94|    // MARK: - Recovery
    95|
    96|    func sendRecoveryEmail(email: String) async -> AuthActionResult {
    97|        isLoading = true
    98|        defer { isLoading = false }
    99|        do {
   100|            try await service.sendRecoveryEmail(email: email)
   101|            return AuthActionResult(success: true, message: "Reset email sent.")
   102|        } catch {
   103|            return AuthActionResult(success: false, message: error.localizedDescription)
   104|        }
   105|    }
   106|
   107|    // MARK: - Repair (V7 emergency)
   108|
   109|    func repairOwner(email: String, newPassword: String) async -> AuthActionResult {
   110|        isLoading = true
   111|        defer { isLoading = false }
   112|        do {
   113|            let message = try await service.repairOwner(email: email, newPassword: newPassword)
   114|            return AuthActionResult(success: true, message: message)
   115|        } catch {
   116|            return AuthActionResult(success: false, message: error.localizedDescription)
   117|        }
   118|    }
   119|
   120|    // MARK: - Diagnostic
   121|
   122|    func fetchDiagnostic() async {
   123|        do {
   124|            diagnostic = try await service.fetchDiagnostic()
   125|        } catch {
   126|            diagnostic = nil
   127|        }
   128|    }
   129|
   130|    // MARK: - Logout
   131|
   132|    func logout() {
   133|        clearSession()
   134|        state = .unauthenticated
   135|    }
   136|
   137|    // MARK: - Clear Error
   138|
   139|    func clearError() {
   140|        if case .error = state {
   141|            state = .unauthenticated
   142|        }
   143|    }
   144|}

